def build_retriever(index, department: str, year: int, top_k: int = 5):
    filters = MetadataFilters(filters=[
        MetadataFilter(key="department", value=department),
        MetadataFilter(key="fiscal_year", value=year, operator=FilterOperator.GTE),
    ])
    return index.as_retriever(similarity_top_k=top_k, filters=filters)

# Called per-request with user context
retriever = build_retriever(index, department="finance", year=2023, top_k=8)
nodes = retriever.retrieve("operating leverage")
